function gemiddelde(arr) {
  return arr.length ? arr.reduce((a, b) => a + b, 0) / arr.length : 0;
}
function gemiddeldeIngevuld(items) {
  const scores = items.map((i) => i.score).filter((s) => s > 0);
  return scores.length ? gemiddelde(scores) : 0;
}
function statusTag(pct) {
  if (pct < 45) return { label: "aandacht nodig", bg: "#FDE3E3", fg: "#B40000" };
  if (pct < 70) return { label: "in ontwikkeling", bg: "#FFF1C2", fg: "#8a6d00" };
  return { label: "sterk punt", bg: "#E0F3DD", fg: "#1F7A19" };
}
function polair(cx, cy, r, hoekGraden) {
  const hoek = ((hoekGraden - 90) * Math.PI) / 180;
  return [cx + r * Math.cos(hoek), cy + r * Math.sin(hoek)];
}

function CompetentieRoosSvg({ modGem }) {
  const cx = 210, cy = 215, maxR = 150;
  const n = modGem.length;
  const stap = 360 / n;

  const ringen = [0.2, 0.4, 0.6, 0.8, 1].map((f, idx) => {
    const pts = modGem.map((m, i) => polair(cx, cy, maxR * f, i * stap).join(",")).join(" ");
    return <polygon key={idx} points={pts} fill="none" stroke={KLEUR.lijn} strokeWidth="1" />;
  });

  const assen = modGem.map((m, i) => {
    const [x, y] = polair(cx, cy, maxR, i * stap);
    return <line key={i} x1={cx} y1={cy} x2={x} y2={y} stroke={KLEUR.lijn} strokeWidth="1" />;
  });

  const dataPts = modGem.map((m, i) => polair(cx, cy, maxR * (m.gem / 5), i * stap).join(",")).join(" ");

  const stippen = modGem.map((m, i) => {
    const [x, y] = polair(cx, cy, maxR * (m.gem / 5), i * stap);
    const pct = m.gem / 5;
    const kleur = pct < 0.45 ? KLEUR.rood : pct < 0.7 ? "#FFD400" : KLEUR.groen;
    return <circle key={i} cx={x} cy={y} r="6" fill={kleur} stroke="#fff" strokeWidth="1.5" />;
  });

  const labels = modGem.map((m, i) => {
    const [x, y] = polair(cx, cy, maxR + 34, i * stap);
    const tekst = m.naam.length > 16 ? m.naam.slice(0, 15) + "…" : m.naam;
    return (
      <text key={i} x={x} y={y} fontSize="10.5" fontFamily="Arial" fill="#444" textAnchor="middle" dominantBaseline="middle">
        {tekst}
      </text>
    );
  });

  return (
    <svg viewBox="0 0 420 420" className="w-full max-w-[420px] h-auto" role="img" aria-label="Competentieroos: scores per module weergegeven als spinnenwebgrafiek">
      <title>Competentieroos</title>
      {ringen}
      {assen}
      <polygon points={dataPts} fill={KLEUR.blauw} fillOpacity="0.22" stroke={KLEUR.blauw} strokeWidth="2.5" />
      {stippen}
      {labels}
      <circle cx={cx} cy={cy} r="14" fill={KLEUR.geel} stroke={KLEUR.blauw} strokeWidth="2" />
    </svg>
  );
}

function Meter({ pct, kleur }) {
  return (
    <div className="h-2.5 rounded-full overflow-hidden" style={{ background: KLEUR.zandDeep }}>
      <div className="h-full rounded-full transition-all duration-300" style={{ width: `${pct}%`, background: kleur || KLEUR.blauw }} />
    </div>
  );
}

